/**
 * SwarmX logo assets, embedded as base64 PNGs so the deploy bundle
 * (src + server.ts) never depends on loose image files.
 * Source: swarm2.jpg (2026-07-17 rebrand) — red hex-cluster X mark on black.
 */

/** 64x64 favicon PNG (base64). */
export const LOGO_FAVICON_B64 = "";

/** 192x192 nav/header logo PNG (base64). */
export const LOGO_NAV_B64 = "";

export function logoBytes(b64: string): Uint8Array {
  return Uint8Array.from(atob(b64), (c) => c.charCodeAt(0));
}

/** 1200x630 Open Graph / Twitter share card JPEG (base64). Source: live hero capture 2026-07-17. */
export const OG_CARD_B64 = "";
